 1	import React, { FC, useState } from 'react';
 2	
 3	import { Button, ButtonVariant, Text } from '@patternfly/react-core';
 4	import { PlusCircleIcon } from '@patternfly/react-icons/dist/esm/icons/plus-circle-icon';
 5	import LabelSelectorEditor from '@utils/components/LabelSelectorEditor/LabelSelectorEditor';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	import { isEmpty } from '@utils/utils';
 8	
 9	type NetworkPolicyConditionalSelectorProps = {
10	  dataTest?: string;
11	  helpText: string;
12	  onChange: (pairs: string[][]) => void;
13	  selectorType: 'namespace' | 'pod';
14	  values: string[][];
15	};
16	
17	const NetworkPolicyConditionalSelector: FC<NetworkPolicyConditionalSelectorProps> = ({
18	  dataTest,
19	  helpText,
20	  onChange,
21	  selectorType,
22	  values,
23	}) => {
24	  const { t } = useNetworkingTranslation();
25	  const [isVisible, setVisible] = useState<boolean>(isEmpty(values));
26	
27	  const handleSelectorChange = (nameValuePairs: string[][]) => {
28	    onChange(nameValuePairs);
29	  };
30	
31	  const title = selectorType === 'pod' ? t('Pod selector') : t('Namespace selector');
32	  const addSelectorText =
33	    selectorType === 'pod' ? t('Add pod selector') : t('Add namespace selector');
34	  const secondHelpText =
35	    selectorType === 'pod'
36	      ? t('Pods having all the supplied key/value pairs as labels will be selected.')
37	      : t('Namespaces having all the supplied key/value pairs as labels will be selected.');
38	
39	  return (
40	    <>
41	      <span>
42	        <label>{title}</label>
43	      </span>
44	      <Text component="p">{helpText}</Text>
45	      {isVisible || !isEmpty(values) ? (
46	        <>
47	          <Text component="p">{secondHelpText}</Text>
48	          <LabelSelectorEditor
49	            labelSelectorPairs={!isEmpty(values) ? values : [['', '']]}
50	            onLastItemRemoved={() => setVisible(false)}
51	            updateParentData={handleSelectorChange}
52	          />
53	        </>
54	      ) : (
55	        <Button
56	          className="pf-m-link--align-left"
57	          data-test={dataTest ? `add-${dataTest}` : 'add-labels-selector'}
58	          onClick={() => setVisible(true)}
59	          type="button"
60	          variant={ButtonVariant.link}
61	        >
62	          <PlusCircleIcon className="co-icon-space-r" />
63	          {addSelectorText}
64	        </Button>
65	      )}
66	    </>
67	  );
68	};
69	
70	export default NetworkPolicyConditionalSelector;

